import React, { useState, useEffect } from 'react';
import img1 from '../assets/images/unsplash_9jI4bXu6L-E.jpg';
import img2 from '../assets/images/unsplash_a--1--Cmut8.jpg';
import img3 from '../assets/images/unsplash_pIKQbdSzF_k.png';
import img4 from '../assets/images/image(1).jpg';
import img5 from '../assets/images/image(2).jpg';
import img6 from '../assets/images/image.jpg';
import './DealsOfMonth.css';

const products = [
  { id: 1, img: img1, label: 'Spring Sale',  num: '01', discount: '30% OFF' },
  { id: 2, img: img2, label: 'Summer Deal',  num: '02', discount: '25% OFF' },
  { id: 3, img: img3, label: 'Flash Sale',   num: '03', discount: '40% OFF' },
  { id: 4, img: img4, label: 'Hot Offer',    num: '04', discount: '20% OFF' },
  { id: 5, img: img5, label: 'New Arrival',  num: '05', discount: '15% OFF' },
  { id: 6, img: img6, label: 'Clearance',    num: '06', discount: '50% OFF' },
];

const VISIBLE = 3;

/* Fixed countdown target */
function getTarget() {
  const t = new Date();
  t.setDate(t.getDate() + 2);
  t.setHours(t.getHours() + 6);
  t.setMinutes(t.getMinutes() + 5);
  t.setSeconds(t.getSeconds() + 30);
  return t;
}
const TARGET = getTarget();

function calcTime() {
  const diff = Math.max(0, TARGET - Date.now());
  return {
    days: Math.floor(diff / 86400000),
    hrs:  Math.floor((diff % 86400000) / 3600000),
    mins: Math.floor((diff % 3600000)  / 60000),
    secs: Math.floor((diff % 60000)    / 1000),
  };
}
function pad(n) { return String(n).padStart(2, '0'); }

export default function DealsOfMonth() {
  const [time,  setTime]  = useState(calcTime());
  const [start, setStart] = useState(0);

  const total = products.length;
  const dots  = total - VISIBLE + 1; // 4 dots for 6 items, 3 visible

  useEffect(() => {
    const id = setInterval(() => setTime(calcTime()), 1000);
    return () => clearInterval(id);
  }, []);

  const prev = () => setStart((s) => Math.max(0, s - 1));
  const next = () => setStart((s) => Math.min(total - VISIBLE, s + 1));

  const visible = products.slice(start, start + VISIBLE);

  return (
    <section className="deals-section">

      {/* ── Left panel ── */}
      <div className="deals-left">
        <h2 className="deals-heading">Deals Of The Month</h2>
        <p className="deals-sub">
          "Deals of the Month" means special offers, discounts, or
          promotions that are available for a limited time—
          usually for that specific month.
        </p>
        <button className="deals-shop-btn">SHOP NOW</button>

        <p className="deals-timer-label">Hurry, Before It's Too Late!</p>
        <div className="deals-timer">
          {[
            { val: pad(time.days), unit: 'Days' },
            { val: pad(time.hrs),  unit: 'Hr'   },
            { val: pad(time.mins), unit: 'Mins'  },
            { val: pad(time.secs), unit: 'Sec'   },
          ].map(({ val, unit }) => (
            <div className="timer-box" key={unit}>
              <span className="timer-num">{val}</span>
              <span className="timer-unit">{unit}</span>
            </div>
          ))}
        </div>
      </div>

      {/* ── Right panel ── */}
      <div className="deals-right">

        {/* Product cards */}
        <div className="deals-cards">
          {visible.map((p) => (
            <div className="deal-card" key={p.id}>
              <img src={p.img} alt={p.label} className="deal-card-img" />
              <div className="deal-card-footer">
                <div className="deal-footer-top">
                  <span className="deal-num">{p.num}</span>
                  <span className="deal-divider">——</span>
                  <span className="deal-label">{p.label}</span>
                </div>
                <div className="deal-discount">{p.discount}</div>
              </div>
            </div>
          ))}
        </div>

        {/* Controls: arrows LEFT, dots RIGHT */}
        <div className="deals-controls">
          <div className="deals-arrows">
            <button
              className="deals-arrow"
              onClick={prev}
              disabled={start === 0}
              aria-label="Previous"
            >‹</button>
            <button
              className="deals-arrow"
              onClick={next}
              disabled={start >= total - VISIBLE}
              aria-label="Next"
            >›</button>
          </div>

          <div className="deals-dots">
            {Array.from({ length: dots }).map((_, i) => (
              <button
                key={i}
                className={`deals-dot ${i === start ? 'active' : ''}`}
                onClick={() => setStart(i)}
                aria-label={`Go to group ${i + 1}`}
              />
            ))}
          </div>
        </div>

      </div>
    </section>
  );
}
